/* global chrome */

let tooltip = null;

// Listen for when the user finishes selecting text
document.addEventListener('mouseup', (event) => {
  const selectedText = window.getSelection().toString().trim();
  
  // If text is selected, send it to the service worker for explanation
  if (selectedText.length > 2 && selectedText.length < 100) {
    chrome.runtime.sendMessage({ type: 'EXPLAIN_TEXT', text: selectedText });
  }
});

// Listen for the explanation message from the service worker
chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  if (message.type === 'SHOW_EXPLANATION') {
    displayTooltip(message.explanation);
  }
});

// Function to create and display the tooltip
function displayTooltip(text) {
  // Remove any existing tooltip
  if (tooltip) {
    tooltip.remove();
  }

  // Create the tooltip element
  tooltip = document.createElement('div');
  tooltip.textContent = text;
  
  // Style the tooltip
  Object.assign(tooltip.style, {
    position: 'fixed',
    top: '20px',
    right: '20px',
    backgroundColor: '#fff',
    border: '1px solid #ccc',
    borderRadius: '8px',
    padding: '12px',
    boxShadow: '0 4px 8px rgba(0,0,0,0.1)',
    zIndex: '10000',
    maxWidth: '300px',
    fontSize: '14px',
    lineHeight: '1.5',
    color: '#333'
  });

  document.body.appendChild(tooltip);

  // Remove the tooltip after 7 seconds
  setTimeout(() => {
    if (tooltip) {
      tooltip.remove();
      tooltip = null;
    }
  }, 7000);
}

/* global chrome */

// Open the side panel on the toolbar icon click
chrome.action.onClicked.addListener((tab) => {
  chrome.sidePanel.open({ tabId: tab.id });
});

// Main listener for messages from UI or content scripts
chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  // Use a switch statement to handle different message types
  switch (message.type) {
    case 'SUMMARIZE_PAGE':
      handleSummarizePage(sender.tab.id);
      break;
    case 'EXPLAIN_TEXT':
      handleExplainText(message.text, sender.tab.id);
      break;
  }
  // Return true to indicate that sendResponse will be called asynchronously
  return true;
});

// Function to handle summarizing the page
async function handleSummarizePage(tabId) {
  try {
    // Get the main text content from the page
    const results = await chrome.scripting.executeScript({
      target: { tabId: tabId },
      func: () => document.body.innerText,
    });
    const pageText = results.result;

    // Split text into manageable chunks (e.g., by paragraphs)
    const chunks = pageText.split('\n\n').filter(chunk => chunk.trim().length > 100);

    // Use the Summarizer API for each chunk
    for (const chunk of chunks) {
      if (self.ai && (await self.ai.canCreateSummarizer())) {
        const summarizer = await self.ai.createSummarizer();
        const result = await summarizer.summarize(chunk);
        // Send each summary point back to the side panel
        chrome.runtime.sendMessage({ type: 'GIST_SUMMARY_RESULT', summary: result.summary });
      }
    }
  } catch (error) {
    console.error("Error summarizing page:", error);
    chrome.runtime.sendMessage({ type: 'GIST_SUMMARY_RESULT', summary: "Error: Could not summarize." });
  }
}

// Function to handle explaining selected text
async function handleExplainText(text, tabId) {
  try {
    // Check if the Prompt API is available
    if (self.ai && (await self.ai.canCreateTextSession()) === 'readily') {
      const session = await self.ai.createTextSession();
      const prompt = `Explain the following term or phrase in one simple sentence for a non-expert: "${text}"`;
      
      // Stream the response from the AI model
      const stream = session.promptStreaming(prompt);
      let fullResponse = "";
      for await (const chunk of stream) {
        fullResponse += chunk;
      }
      
      // Send the complete explanation back to the content script
      chrome.tabs.sendMessage(tabId, {
        type: 'SHOW_EXPLANATION',
        explanation: fullResponse,
      });
      session.destroy();
    }
  } catch (error) {
    console.error("Error explaining text:", error);
  }
}
